# Minimal ReAct-style agent loop — the core pattern an AI Agent Engineer builds and maintains
import anthropic
import json
from typing import Any

client = anthropic.Anthropic()

tools = [
    {
        "name": "search_knowledge_base",
        "description": "Search the internal knowledge base for relevant documents.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "The search query."}
            },
            "required": ["query"]
        }
    },
    {
        "name": "create_ticket",
        "description": "Create a support ticket with a given summary and priority.",
        "input_schema": {
            "type": "object",
            "properties": {
                "summary": {"type": "string"},
                "priority": {"type": "string", "enum": ["low", "medium", "high"]}
            },
            "required": ["summary", "priority"]
        }
    }
]

def dispatch_tool(name: str, inputs: dict[str, Any]) -> str:
    """Route tool calls to their implementations."""
    if name == "search_knowledge_base":
        # Real implementation would query a vector DB
        return f"Found 3 articles matching '{inputs['query']}'"
    elif name == "create_ticket":
        return f"Ticket created: {inputs['summary']} [priority={inputs['priority']}]"
    return "Unknown tool"

def run_agent(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]

    for _ in range(10):  # max iterations — always cap the loop
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            tools=tools,
            messages=messages,
            system="You are a helpful support agent. Use tools to resolve user issues."
        )

        if response.stop_reason == "end_turn":
            # Extract final text response
            for block in response.content:
                if block.type == "text":
                    return block.text
            return ""

        # Process tool use blocks
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result
                })

        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})

    return "Agent reached max iterations without completing the task."

result = run_agent("My order #12345 has not arrived and it has been 10 days.")
print(result)

# A well-engineered tool implementation: typed, bounded, and explicit on failure
from dataclasses import dataclass
from typing import Optional
import httpx

@dataclass
class SearchResult:
    title: str
    url: str
    snippet: str

def search_web(query: str, max_results: int = 5) -> list[SearchResult] | str:
    """
    Search the web for the given query.
    Returns a list of SearchResult objects, or an error string on failure.

    - max_results is capped at 10 to prevent runaway cost.
    - Timeouts are enforced; the caller (agent loop) sees a clear error, not a hang.
    """
    if not query or not query.strip():
        return "Error: query must be a non-empty string."
    max_results = min(max_results, 10)  # hard cap

    try:
        with httpx.Client(timeout=5.0) as client:
            response = client.get(
                "https://api.search.example.com/v1/search",
                params={"q": query, "limit": max_results},
                headers={"Authorization": "Bearer " + get_api_key()}
            )
        response.raise_for_status()
        data = response.json()
        return [
            SearchResult(title=r["title"], url=r["url"], snippet=r["snippet"])
            for r in data.get("results", [])
        ]
    except httpx.TimeoutException:
        return "Error: search timed out after 5 seconds."
    except httpx.HTTPStatusError as e:
        return f"Error: search API returned {e.response.status_code}."
    except Exception as e:
        return f"Error: unexpected failure — {type(e).__name__}."


def get_api_key() -> str:
    import os
    key = os.environ.get("SEARCH_API_KEY")
    if not key:
        raise EnvironmentError("SEARCH_API_KEY not set")
    return key
